const d = $input.item.json.body || $input.item.json;

// 1. Tính toán & Định dạng tiền
const tongTien = d.tongTien || 3500000; // Mặc định nếu API ko truyền
d.tongTienDep = new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(tongTien);

// 2. Tạo Link VietQR
const bankCode = 'MB';
const accNumber = '0905881525';
const accName = 'HUYNH NGOC HUY';
const content = `ThanhToan_Phong_${d.phong || 'PT'}`;
d.qrCodeUrl = `https://img.vietqr.io/image/${bankCode}-${accNumber}-compact2.png?amount=${tongTien}&addInfo=${content}&accountName=${accName}`;

const today = new Date();
const dateStr = today.toLocaleDateString('vi-VN');

// 3. Khung HTML Hóa đơn chuẩn
const htmlInvoice = `<!DOCTYPE html>
<html lang="vi">
<head>
<meta charset="UTF-8">
<style>
  @page { size: A4; margin: 20mm; }
  body { font-family: "Arial", sans-serif; color: #333; line-height: 1.4; }
  .header { border-bottom: 2px solid #1e40af; padding-bottom: 10px; margin-bottom: 20px; }
  .header h1 { color: #1e40af; margin: 0; font-size: 24px; text-transform: uppercase; }
  table { width: 100%; border-collapse: collapse; margin-bottom: 20px; }
  th, td { padding: 10px; text-align: left; border-bottom: 1px solid #ddd; }
  th { background-color: #f8fafc; }
  .total { font-size: 20px; font-weight: bold; color: #dc2626; text-align: right; }
  .qr-section { text-align: center; margin-top: 30px; }
  .qr-section img { width: 220px; border: 2px solid #1e40af; border-radius: 10px; padding: 10px; }
</style>
</head>
<body>
  <div class="header">
    <h1>HÓA ĐƠN TIỀN TRỌ - THÁNG ${today.getMonth() + 1}/${today.getFullYear()}</h1>
    <p>Ngày lập: ${dateStr} | <b>Phòng: ${d.phong || '...'}</b></p>
  </div>
  <p><b>Khách hàng:</b> ${d.hoTen || 'Khách thuê'}</p>
  <table>
    <tr><th>Hạng mục</th><th>Số lượng/Chỉ số</th><th>Thành tiền</th></tr>
    <tr><td>Tiền phòng</td><td>1 tháng</td><td>... đ</td></tr>
    <tr><td>Tiền điện</td><td>${d.soDien ? d.soDien + ' kWh' : 'Khoán'}</td><td>... đ</td></tr>
    <tr><td>Tiền nước</td><td>${d.soNuoc ? d.soNuoc + ' m3' : 'Khoán'}</td><td>... đ</td></tr>
  </table>
  <div class="total">TỔNG THANH TOÁN: ${d.tongTienDep}</div>
  <div class="qr-section">
    <h3>MÃ QR THANH TOÁN</h3>
    <img src="${d.qrCodeUrl}" alt="Mã QR">
    <p><i>Cảm ơn quý khách!</i></p>
  </div>
</body>
</html>`;

// 4. Đóng gói cho Gotenberg
return {
  json: d,
  binary: {
    indexHtml: {
      data: Buffer.from(htmlInvoice, 'utf-8').toString('base64'),
      mimeType: 'text/html',
      fileName: 'invoice.html'
    }
  }
};

const pdfFile = $input.item.binary?.data;
if (!pdfFile) throw new Error("Gotenberg lỗi!");

const fileBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const pdfBase64 = fileBuffer.toString('base64');
const prevData = $('Tạo HTML & Tính QR').item.json;

return {
  json: { ...prevData, pdfBase64: pdfBase64 },
  binary: {
    data: {
      data: pdfBase64,
      mimeType: 'application/pdf',
      fileName: `HoaDon_P${prevData.phong || 'X'}.pdf`,
      fileExtension: 'pdf'
    }
  }
};
